function removeLastParenthesis(text) {
    return text.replace(/\s*\([^)]*\)\s*$/, '');
}

function removeFirst3FAndLastParenthesis(text) {
    // Remove the first occurrence of "3F"
    let result = text.replace(/^3F\s*/, '');

    return result;
}

const deviceName = removeLastParenthesis(msg.payload.name);

let device = devices[deviceName];

if (!device) {
    const technicalAlternative = devices[removeFirst3FAndLastParenthesis(deviceName)];
    if (!technicalAlternative) {
        node.warn('Device not found!! ' + deviceName);
        return null;
    }

    device = technicalAlternative;
}

mappedDevices[deviceName] = msg.payload;

global.set('thingsboardMappedDevices', mappedDevices);

return {
    payload: {
        key: 'thingsboardMappedDevices',
        value: mappedDevices,
    },
};

