const isMultiple = slave.name.indexOf('/') >= 0;

function getCleanName(roomName, slaveName) {
    const isAc = slaveName.toLowerCase().indexOf('ar') > -1
    let name = roomName.replace(/3F/, '');
    name = name.replace(/Ar/gi, '');
    name = name.trimStart().trim();

    if (isAc) {
        name = `Ar ${name}`;
    } else {
        name = `3F ${name}`;
    }

    return name;
}

if (!isMultiple) {
    devices[getCleanName(slave.name, slave.name)] = {
        version: slave.version,
        temperature_correction: slave.temperature_correction,
        deviceKind: 'energy'
    };
} else {
    // Send each one
    const rooms = slave.name.split('/');

    for (let i = 0; i < rooms.length; i++ ) {
        const name = getCleanName(rooms[i], slave.name);
        if (name.indexOf('NADA') > -1) continue;
        if (name.indexOf('Nada') > -1) continue;

        devices[name] = {
            version: slave.version,
            temperature_correction: slave.temperature_correction,
            deviceKind: 'energy'
        };
    }
}

