const devices = Object.keys(msg.payload);
const alarms = flow.get('stored_alarms') || {};

const shouldCreate = [];
const shouldClose = [];

for (device of devices) {
    const stateUpdate = msg.payload[device][0].values;

    if (alarms[device]) {
        for (alarm of alarms[device]) {
            switch (alarm.type) {
                case 'deviceActivated': {
                    if (stateUpdate.status === 'on'
                        || stateUpdate.status === 'detected') {
                        shouldCreate.push({
                            status: stateUpdate.status,
                            deviceName: device,
                            users: alarm.users,
                            type: alarm.type,
                            customerId: alarm.customerId,
                            message: alarm.message,
                        });
                    } else {
                        shouldClose.push({
                            status: stateUpdate.status,
                            deviceName: device,
                            users: alarm.users,
                            type: alarm.type,
                            customerId: alarm.customerId,
                            message: alarm.message,
                        });
                    }
                } break;
                case 'deviceDeactivated': {
                    if (stateUpdate.status === 'off'
                        || stateUpdate.status === 'not_detected') {
                        shouldCreate.push({
                            status: stateUpdate.status,
                            deviceName: device,
                            users: alarm.users,
                            type: alarm.type,
                            customerId: alarm.customerId,
                            message: alarm.message,
                        });
                    } else {
                        shouldClose.push({
                            status: stateUpdate.status,
                            deviceName: device,
                            users: alarm.users,
                            type: alarm.type,
                            customerId: alarm.customerId,
                            message: alarm.message,
                        });
                    }
                } break;
                default:
                break;
            }
        }
    }
}

if (shouldCreate.length <= 0 && shouldClose.length <= 0) {
    return null;
}

return [{
    payload: shouldCreate
}, {
    payload: shouldClose
}];

