const devices = {};

function getDeviceReading(type, payload) {
    if (!payload) return null;
    if (type === 'lamp' || type === 'plug') {
        return payload.output === 100 ? "on": "off";
    } else if (type === 'presence_sensor') {
        return payload.input === 100 ? "detected" : "not_detected";
    } else if (type === 'door_sensor') {
        return payload.input === 100 ? "open" : "closed";
    }

    return payload.output === 100 ? 'on' : 'off';
}

if (slave.type === 'infrared') {
    const name = slave.name.trimStart().trim();
    devices[name] = [{
        status: getDeviceReading('presence_sensor', lastReading.channels[0]),
    }]
} else {
    for (let i = 0; i < channelsList.length; i++) {
        const channel = channelsList[i];
        const name = channel.name.trimStart().trim();

        const reading = getDeviceReading(channel.type, lastReading.channels[channel.channel]);

        msg.debug = {
            reading,
            name,
            channel,
            lastReading
        }

        if (!reading) continue;

        devices[name] = [{
            "ts": new Date().getTime(),
            "values": {
                "status": reading
            }
        }];
    }
}

